const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer data
    // This is where reading should start
    return buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer data
    // This allows writing/modifying existing buffer content
    return buffer.data();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Calculate and return buffer space information
    BufferInfo info;
    info.readable_size = buffer.size();  // Current amount of data in buffer
    info.free_space = buffer.capacity() - buffer.size();  // Available space without reallocation
    return info;
}
```

