template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    if constexpr (from == to) {
        // No conversion needed if endianness is the same
        return value;
    } else if constexpr ((from == std::endian::little && to == std::endian::big) ||
                         (from == std::endian::big && to == std::endian::little)) {
        // Swap bytes when converting between little and big endian
        return hexi::byteswap(value);
    } else if constexpr (from == std::endian::native) {
        // Converting from native endianness
        if constexpr (to == std::endian::big) {
            return hexi::native_to_big_endian(value);
        } else if constexpr (to == std::endian::little) {
            return hexi::native_to_little_endian(value);
        }
    } else if constexpr (to == std::endian::native) {
        // Converting to native endianness
        if constexpr (from == std::endian::big) {
            return hexi::big_endian_to_native(value);
        } else if constexpr (from == std::endian::little) {
            return hexi::little_endian_to_native(value);
        }
    }
    return value;
}

template<typename T>
