```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Get the actual amount of readable data available
    size_t available = storage.size();
    size_t to_copy = std::min(bytes_to_preview, available);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result(to_copy);

    // Preview data without consuming (peek doesn't advance read pointer)
    if (to_copy > 0) {
        storage.peek(result.data(), to_copy);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get readable data size (amount of data available to read)
    status.readable_size = storage.size();

    // Calculate free space (total capacity minus current data size)
    status.free_space = storage.capacity() - storage.size();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets to initial state
    storage.clear();
}
```

