#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Convert to unsigned for proper bit manipulation
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT uvalue = static_cast<UnsignedT>(value);

    std::size_t bytes_written = 0;

    // Write bytes with continuation bit while value >= 0x80
    while (uvalue >= 0x80) {
        uint8_t byte = static_cast<uint8_t>((uvalue & 0x7F) | 0x80);
        writer.write(&byte, 1);
        uvalue >>= 7;
        bytes_written++;
    }

    // Write the last byte (no continuation bit)
    uint8_t byte = static_cast<uint8_t>(uvalue & 0x7F);
    writer.write(&byte, 1);
    bytes_written++;

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT result = 0;
    int shift = 0;

    uint8_t byte;
    do {
        reader.read(&byte, 1);
        // Extract lower 7 bits and add to result with appropriate shift
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;
        shift += 7;
    } while (byte & 0x80);  // Continue if continuation bit is set

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;

    // Create a buffer adaptor
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
    {
        hexi::pmc::binary_stream_writer writer(adaptor);
        encode_varint(writer, original_value);
    }

    // Decode the value
    T decoded_value;
    {
        hexi::pmc::binary_stream_reader reader(adaptor);
        decoded_value = decode_varint<T>(reader);
    }

    // Compare with original
    return decoded_value == original_value;
}
```

