using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Empty regions don't overlap
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert to byte pointers for arithmetic comparison
    const auto* src_begin = static_cast<const unsigned char*>(src);
    const auto* src_end = src_begin + src_len;

    const auto* dst_begin = static_cast<const unsigned char*>(dst);
    const auto* dst_end = dst_begin + dst_len;

    // Two regions overlap if:
    // - src starts before dst ends AND
    // - dst starts before src ends
    return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Zero-length copy is trivially safe and successful
    if (length == 0) {
        return true;
    }

    // Check for null pointers
    if (!destination || !source) {
        return false;
    }

    // Check for overlap - overlapping regions make the copy unsafe
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlap detected, unsafe to copy with memcpy
    }

    // No overlap detected, safe to perform the copy
    std::memcpy(destination, source, length);
    return true;
}
