    // Attempt to read, catch stream_read_limit if it occurs
    try {
        stream.read(destination, length);
        // Read succeeded, no exception
        return ReadLimitInfo{0, 0, 0, false};
    } catch (const hexi::exception::stream_read_limit& e) {
        // Read limit exceeded, extract exception information
        return ReadLimitInfo{
            e.read_size(),
            e.total_read(),
