    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    hexi::Writer writer;

    // Write header (uint16_t)
    writer.write(packet.header);

    // Write data string (with length prefix)
    writer.write(packet.data);

    // Write 16 bytes of padding filled with 0x00
    writer.fill<16>(0x00);

    // Write footer (uint32_t)
    writer.write(packet.footer);

